  ('promotion-7fec267e-moex-00013', 'promotion-7fec267e', 'promotion-7fec267e-moex-114-3a7b2121', 'sub-promotion-7fec267e-03', NULL, 'single_choice', '美國的「黑堡宣言」主張公共行政人員應該具備負責任的專業精神，並認為此種精神才是專業主 義的表現。下列那一項行政行為不符合所謂「負責任的專業精神」之意義？', '["勇於對長官違背憲政精神的政策說不", "對於民眾之需求毫無保留的予以滿足", "面對利益團體的壓力仍堅守公共利益", "運用專業能力捍衛民主憲政之目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:40+00:00", "source_pdf_sha1": "92be47b32fd9", "answer_pdf_sha1": "1af9ad3f7a70", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "101", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般行政"}'::jsonb, NULL),
